```aether:src/types.ts
/**
 * Defines the structure for a file record stored in the database.
 */
export interface FileRecord {
  id: string;
  name: string;
  mimeType: string;
  size: number; // in bytes
  objectStorageId: string; // ID or path in object storage
  uploadedAt: Date;
}

/**
 * Defines the structure for creating a new file record.
 */
export type NewFileRecord = Omit<FileRecord, 'id' | 'uploadedAt'>;

/**
 * Defines the structure for a file received from a multipart form.
 * This aligns with the standard `File` interface in browsers/Node.js environments.
 */
export interface UploadedFile {
  name: string;
  type: string; // MIME type
  size: number; // in bytes
  arrayBuffer(): Promise<ArrayBuffer>;
  // Hono's File type also has `lastModified` and `webkitRelativePath` but we don't need them for this feature.
}
```
```aether:src/utils/validation.ts
import { UploadedFile } from '../types';

// Configuration for file validation
const MAX_FILE_SIZE_BYTES = 5 * 1024 * 1024; // 5 MB
const ALLOWED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'application/pdf',
  'text/plain',
];

/**
 * Validates the size of an uploaded file.
 * @param fileSize The size of the file in bytes.
 * @returns True if the file size is valid, false otherwise.
 */
export function validateFileSize(fileSize: number): boolean {
  return fileSize > 0 && fileSize <= MAX_FILE_SIZE_BYTES;
}

/**
 * Validates the MIME type of an uploaded file.
 * @param mimeType The MIME type string of the file.
 * @returns True if the MIME type is allowed, false otherwise.
 */
export function validateMimeType(mimeType: string): boolean {
  return ALLOWED_MIME_TYPES.includes(mimeType);
}

/**
 * Performs all necessary validations for an uploaded file.
 * @param file The uploaded file object.
 * @throws Error if validation fails.
 */
export function validateUploadedFile(file: UploadedFile): void {
  if (!file) {
    throw new Error('No file provided.');
  }
  if (!validateFileSize(file.size)) {
    throw new Error(
      `File size exceeds the maximum allowed (${
        MAX_FILE_SIZE_BYTES / (1024 * 1024)
      } MB) or is empty.`
    );
  }
  if (!validateMimeType(file.type)) {
    throw new Error(
      `File type '${file.type}' is not allowed. Allowed types: ${ALLOWED_MIME_TYPES.join(
        ', '
      )}.`
    );
  }
}
