import { v4 as uuidv4 } from 'uuid';

/**
 * A mock object storage service. In a real application, this would interact
 * with a cloud provider like AWS S3, Google Cloud Storage, or Azure Blob Storage.
 */
class ObjectStorageService {
  private storage: Map<string, ArrayBuffer> = new Map();

  /**
   * Uploads a file to mock object storage.
   * @param fileName The original name of the file.
   * @param mimeType The MIME type of the file.
   * @param data The file content as an ArrayBuffer.
   * @returns A unique ID representing the stored object.
   */
  public async upload(
    fileName: string,
    mimeType: string,
    data: ArrayBuffer
  ): Promise<string> {
    // Simulate network delay
    await new Promise((resolve) => setTimeout(resolve, 100));

    const objectId = `obj-${uuidv4()}-${fileName}`;
    this.storage.set(objectId, data);
    console.log(
      `[ObjectStorage] Stored object: ${objectId} (Type: ${mimeType}, Size: ${data.byteLength} bytes)`
    );
    return objectId;
  }

  /**
   * Retrieves a file from mock object storage.
   * (Not directly used by the upload feature, but good for completeness)
   * @param objectId The ID of the object to retrieve.
   * @returns The file content as an ArrayBuffer, or undefined if not found.
   */
  public async get(objectId: string): Promise<ArrayBuffer | undefined> {
    await new Promise((resolve) => setTimeout(resolve, 50));
    return this.storage.get(objectId);
  }

  /**
   * Deletes a file from mock object storage.
   * (Not directly used by the upload feature, but good for completeness)
   * @param objectId The ID of the object to delete.
   * @returns True if deleted, false if not found.
   */
  public async delete(objectId: string): Promise<boolean> {
    await new Promise((resolve) => setTimeout(resolve, 50));
    return this.storage.delete(objectId);
  }
}

export const objectStorageService = new ObjectStorageService();
