import { v4 as uuidv4 } from 'uuid';
import { FileRecord, NewFileRecord } from '../types';

/**
 * A mock database service for file records. In a real application, this would
 * interact with a relational database (e.g., PostgreSQL, MySQL) or a NoSQL database.
 */
class DatabaseService {
  private files: Map<string, FileRecord> = new Map();

  /**
   * Creates a new file record in the mock database.
   * @param newFile The data for the new file record.
   * @returns The created FileRecord with its generated ID and timestamp.
   */
  public async createFileRecord(newFile: NewFileRecord): Promise<FileRecord> {
    // Simulate network delay
    await new Promise((resolve) => setTimeout(resolve, 50));

    const fileRecord: FileRecord = {
      ...newFile,
      id: uuidv4(),
      uploadedAt: new Date(),
    };
    this.files.set(fileRecord.id, fileRecord);
    console.log(`[Database] Created file record: ${fileRecord.id}`);
    return fileRecord;
  }

  /**
   * Retrieves a file record by its ID.
   * (Not directly used by the upload feature, but good for completeness)
   * @param id The ID of the file record.
   * @returns The FileRecord, or undefined if not found.
   */
  public async getFileRecord(id: string): Promise<FileRecord | undefined> {
    await new Promise((resolve) => setTimeout(resolve, 20));
    return this.files.get(id);
  }

  /**
   * Deletes a file record by its ID.
   * (Not directly used by the upload feature, but good for completeness)
   * @param id The ID of the file record to delete.
   * @returns True if deleted, false if not found.
   */
  public async deleteFileRecord(id: string): Promise<boolean> {
    await new Promise((resolve) => setTimeout(resolve, 20));
    return this.files.delete(id);
  }
}

export const databaseService = new DatabaseService();
