```aether:src/routes/upload.ts
import { Hono } from 'hono';
import { objectStorageService } from '../services/objectStorage';
import { databaseService } from '../services/database';
import { validateUploadedFile } from '../utils/validation';
import { UploadedFile } from '../types';

const uploadRoutes = new Hono();

/**
 * Handles file uploads.
 * Accepts a multipart form, validates the file, stores it in object storage,
 * and writes a record to the database. Returns the file ID.
 */
uploadRoutes.post('/', async (c) => {
  try {
    const body = await c.req.parseBody();
    const file = body['file'] as UploadedFile | undefined; // Assuming the form field name is 'file'

    if (!file) {
      return c.json({ error: 'No file uploaded or file field name is incorrect.' }, 400);
    }

    // 1. Validate file size and mime type
    try {
      validateUploadedFile(file);
    } catch (validationError: any) {
      return c.json({ error: validationError.message }, 400);
    }

    // 2. Store the file in object storage
    const fileBuffer = await file.arrayBuffer();
    const objectStorageId = await objectStorageService.upload(
      file.name,
      file.type,
      fileBuffer
    );

    // 3. Write a row to the files table
    const fileRecord = await databaseService.createFileRecord({
      name: file.name,
      mimeType: file.type,
      size: file.size,
      objectStorageId: objectStorageId,
    });

    // 4. Return the file ID
    return c.json({ fileId: fileRecord.id }, 201);
  } catch (error: any) {
    console.error('File upload failed:', error);
    return c.json({ error: 'Internal server error during file upload.' }, 500);
  }
});

export default uploadRoutes;
