import uploadRoutes from './routes/upload';

const app = new Hono();

// Mount the upload routes under the /upload path
app.route('/upload', uploadRoutes);

// Basic health check route
app.get('/', (c) => {
  return c.text('Aether File Upload Service is running!');
});

// Catch-all for 404 errors
app.notFound((c) => {
  return c.json({ message: 'Not Found', ok: false }, 404);
});

// Global error handler
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ error: 'An unexpected error occurred.' }, 500);
});

// Export the Hono app for deployment (e.g., with Node.js server or Vercel)
export default app;

// Example of how to run the server in a Node.js environment
